export type SsmlTagDef = {
  tag: string;
  label: string;
  description: string;
  category: 'flow' | 'prosody' | 'pronunciation' | 'identity';
  selfClosing: boolean;
  attributes: SsmlAttrDef[];
  /** providerId → supported. Only SSML-capable providers listed. */
  providers: Record<string, boolean>;
};

